const keywords = ($env.MARKET_KEYWORDS || '').toLowerCase().split(',').map(k=>k.trim()).filter(Boolean);
const weekAgo = new Date(); weekAgo.setDate(weekAgo.getDate()-7);
const allItems = $input.all().map(i=>i.json);
const filtered = allItems.filter(item => {
  const text = ((item.title||'')+(item.contentSnippet||item.content||item.summary||'')).toLowerCase();
  const recent = !item.isoDate || new Date(item.isoDate) >= weekAgo;
  const relevant = keywords.length === 0 || keywords.some(k=>text.includes(k));
  return recent && relevant;
}).slice(0,25);
return [{ json: { week: new Date().toISOString().slice(0,10), count: filtered.length, items: filtered.map(i=>({ title: i.title, link: i.link, date: i.isoDate?.slice(0,10), snippet: (i.contentSnippet||i.summary||'').slice(0,200) })) } }];

