const data = $('Merge and Filter').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { week: data.week, signals_scanned: data.count, generated_at: new Date().toISOString(), ...analysis } }];

